############################################################
## Additional diagnostics for the synthetic weak-overlap experiment
##
## The diagnostics are generated by 01_synthetic_weak_overlap_experiment.R.
## This wrapper is kept so that the repository has a separate entry point
## corresponding to the Supplementary section "Additional diagnostics for
## the synthetic weak-overlap experiment".
############################################################

needed <- c(
  "table_finite_L2grid.csv",
  "table_efficiency_L2grid.csv",
  "fig_rmse_coarse_L2grid.png",
  "fig_tail_q99_coarse_L2grid.png",
  "fig_delta_q95_L2grid.png",
  "fig_L2grid_train_mass.png"
)

missing <- needed[!file.exists(needed)]
if (length(missing) > 0) {
  message("Synthetic diagnostic outputs are missing; running the main synthetic script.")
  source("01_synthetic_weak_overlap_experiment.R")
} else {
  message("Synthetic diagnostic outputs already exist:")
  print(needed)
}
